INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-d0d1b9a2-moex-00390', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'essay', '自民國 104 年起，我國審計準則委員會參酌國際審計準則公報，陸續
發布了審計準則公報第五十八號至第六十號，對會計師財務報表查核
報告做了重大的修訂，請依照相關的規定回答下列問題：
就上市（櫃）公司之查核報告而言，請說明無保留意見查核報告中至
少會包括那些段（section）？（5分）
修正式意見包括那三種類型？並說明造成會計師出具每一種修正式
意見之情況。（9分）
何謂關鍵查核事項（key audit matter）？會計師如何決定關鍵查核事
項？（5分）
何謂強調事項及其他事項？（4 分）
會計師如欲於查核報告中向財務報表使用者說明查核規劃有關重大
性設定及查核範圍時，應在查核報告中的那一段加以說明？（2分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00391', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'essay', '管理階層因其職位通常較有機會踰越形式上有效運作之控制，以偽造
或操弄會計紀錄並編製不實之財務報表。雖然管理階層踰越控制之風
險程度隨受查者而異，但此風險存在於所有受查者中。因此，審計準
則公報第七十四號「查核財務報表對舞弊之責任」規定，查核人員應
將導因於管理階層踰越內部控制之重大不實表達風險視為顯著風險。
試問：不論查核人員對管理階層踰越控制之風險評估結果為何，均應
設計及執行那些查核程序？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00392', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '下列何種情況發生時，會計師應對受查者財務報表出具無法表示意見之查核報告？①受查者管理', '["受查者管理階層未提供查核人員所要求之一項或多項書面聲明", "查 核人員對受查者管理階層之誠信有重大懷疑致其認為所取得之書面聲明並不可靠", "僅", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00393', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依據審計準則公報第五十八號之規定，有關查核報告中「關鍵查核事項」之溝通，下列敘述何者正 確？', '["關鍵查核事項可用以取代導致保留意見之事項", "當出具否定意見之查核報告時，不得於查核報告中溝通關鍵查核事項", "會計師將某複雜金融商品之公允價值評價列為關鍵事項時，可於該事項中強調其已委任專家協 助查核", "會計師查核上市公司財務報表，經決定未有須溝通關鍵查核事項時，則查核報告可刪除關鍵查 核事項段落"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00394', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '有關會計師對繼續經營能力之評估，下列敘述何者錯誤？', '["會計師對繼續經營能力之合理性加以評估後，若能消除其疑慮時，可出具無保留意見之查核報告", "會計師若確定受查者不具繼續經營能力，管理階層仍依IFRS（或企業會計準則）編製財務報表， 應出具否定意見之查核報告", "會計師若確定受查者不具繼續經營能力，受查者財務報表已依清算會計編製，為強調此一事實， 應出具無保留意見之查核報告，並於強調事項段說明相關事實", "會計師對繼續經營能力之合理性加以評估後，仍無法清除其疑慮時，若受查者財務報表未作適 當揭露，會計師應視影響重大程度出其保留意見或無法表示意見之查核報告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00395', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '下列關於會計師保密的敘述，何者錯誤？', '["其不得違反與委託人間應有之信守，若雙方關係已告終止，當委託人提出保密之主張時，其保 密責任方應繼續", "除非法律禁止，其承辦案件，主管機關認有必要，向其查詢或調閱有關資料，其應依法辦理並 通知委託人", "其不得藉其業務上獲知之秘密，對委託人或第三者有任何不良之企圖", "其對承辦案件，不得為其個人或第三者利益，而利用其經辦業務所獲資料，對委託人或第三者 有任何不良企圖"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00396', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '執行審計抽樣時，為何須適當界定母體？', '["才能決定最適當的樣本數", "確保每個抽出來的樣本可以運用最適當的查核程序", "提高取得具代表性樣本之機率，以符合抽樣的目的", "降低無法辨識出科目餘額存有重大錯誤的機率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00397', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '下列有關顯著風險之敘述，何者錯誤？', '["查核人員於判斷所辨認之風險是否為顯著風險時，不應考慮與該項風險有關之控制所能降低風 險之效果", "經由系統自動處理之例行且非複雜交易較不會產生顯著之風險", "管理階層逾越控制之風險，為導因於舞弊之重大不實表達之顯著風險", "查核人員所辨認顯著風險之相關控制於本年度並未發生改變，可直接採用上年度控制測試之查 核證據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00398', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '會計師於考量財務報導舞弊時，下列何者通常不是會計師整舞弊風險資訊的來源？', '["函詢主管機關有關客戶違反法令情形及違規樣態", "客戶所發布公開資訊之分析性評估", "向管理階層詢問", "查核團隊間的溝通討論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL),
  ('retired-d0d1b9a2-moex-00399', 'retired-d0d1b9a2', 'retired-d0d1b9a2-moex-110-0e802df0', 'sub-retired-d0d1b9a2-07', NULL, 'single_choice', '依審計準則公報第六十七號規定，下列何者相對而言並非關係人交易之查核重點？', '["向受查公司取得依規定該公司應建立的「關係人名單清冊」", "向受查公司取得所有關係人交易均為「公平交易」之客戶聲明書", "向受查公司管理階層查詢，該公司對關係人交易授權及核准之內部控制制度", "關係人否決管理階層或治理單位所作之重大營運決策"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:13+00:00", "source_pdf_sha1": "d5e4945287e5", "answer_pdf_sha1": "9065a5cc7538", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "136", "s": "1903", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "會計"}'::jsonb, NULL)
